// Проверяем статус сессии: idle = завершена.
// Если сессия не найдена в statusMap — она могла завершиться и OpenCode её убрал.

const input = $('Формируем промпт верификации').item.json
const sessionId = String(input.sessionId || '').trim()

const statusMap = $('Проверяем статус сессии').item.json || {}
const sessionStatus = statusMap[sessionId]

if (!sessionStatus || Object.keys(sessionStatus).length === 0) {
  return {
    json: { isIdle: false, sessionMissingHint: true },
  }
}

const statusType = String(sessionStatus.type || '').trim()
return {
  json: { isIdle: statusType === 'idle' },
}

// Извлекаем вердикт из ответа DeepSeek.

const toText = (v) => String(v ?? '').trim()

let rawOutput = {}
try { rawOutput = $('DeepSeek Judge').first().json } catch (_) {}
const content = toText(rawOutput.output ?? rawOutput.text ?? '')

if (!content) {
  return { json: { verdict: 'FAILED', reason: 'DeepSeek вернул пустой ответ', fixNeeded: true } }
}

function extractJson(text) {
  const stripped = text.replace(/```(?:json)?\n?/g, '').replace(/```/g, '').trim()
  try { return JSON.parse(stripped) } catch (_) {}
  const start = text.indexOf('{')
  if (start === -1) return null
  let depth = 0, inString = false, escape = false
  for (let i = start; i < text.length; i++) {
    const ch = text[i]
    if (escape) { escape = false; continue }
    if (ch === '\\') { escape = true; continue }
    if (ch === '"') { inString = !inString; continue }
    if (inString) continue
    if (ch === '{') depth++
    if (ch === '}') {
      depth--
      if (depth === 0) {
        try { return JSON.parse(text.slice(start, i + 1)) } catch (_) { return null }
      }
    }
  }
  return null
}

const parsed = extractJson(content)
if (!parsed) {
  const looksPassed = content.toLowerCase().includes('passed') && !content.toLowerCase().includes('failed')
  return {
    json: {
      verdict: looksPassed ? 'PASSED' : 'FAILED',
      reason: content.slice(0, 300),
      fixNeeded: !looksPassed
    }
  }
}

const parentInput = $('Извлекаем текст верификации').first().json

return {
  json: {
    verdict: String(parsed.verdict || '').toUpperCase(),
    reason: String(parsed.reason || ''),
    taskKey: parentInput.taskKey,
    chatId: parentInput.chatId,
    originalPrompt: parentInput.originalPrompt,
    acceptanceCriteria: parentInput.acceptanceCriteria,
    workerAlias: parentInput.workerAlias,
    fixNeeded: String(parsed.verdict || '').toUpperCase() !== 'PASSED',
  },
}

