// Возвращаем финальный результат верификации.

const verifierOutput = $('Извлекаем вердикт').first().json

if (verifierOutput.fixNeeded) {
  const fixData = $('Готовим задачу-фикс').first().json
  return {
    json: {
      verdict: 'FAILED',
      reason: verifierOutput.reason,
      fixTaskKey: fixData.fixTaskKey,
      parentTaskKey: verifierOutput.taskKey,
    }
  }
}

return {
  json: {
    verdict: 'PASSED',
    reason: verifierOutput.reason,
    parentTaskKey: verifierOutput.taskKey,
  }
}
